// frontend/src/App.js
import React, { useEffect, useState } from 'react';
import Cultura from './pages/Cultura'; // Asegúrate de que la ruta sea correcta
import { obtenerSitios } from './services/culturaService';

function App() {
  const [sitios, setSitios] = useState([]);

  useEffect(() => {
    const cargarDatos = async () => {
      const datos = await obtenerSitios();
      setSitios(datos || []);
    };
    cargarDatos();
  }, []);

  return (
    <div className="App">
      {/* 
          Aquí usamos 'sitios'. Al ponerlo aquí, 
          el error de "never used" desaparecerá.
      */}
      <Cultura sitios={sitios} /> 
    </div>
  );
}

export default App; // Esto arregla el error de "'App' is defined but never used"
